    source:
      '"use client";\n\nimport type {Key} from "@thenamespace/uikit";\n\nimport {Autocomplete, EmptyState, Label, ListBox, SearchField, useFilter} from "@thenamespace/uikit";\nimport {Icon} from "@iconify/react";\nimport {useState} from "react";\n\nexport function CustomIndicator() {\n  const [selectedKey, setSelectedKey] = useState<Key | null>(null);\n  const {contains} = useFilter({sensitivity: "base"});\n\n  const items = [\n    {id: "florida", name: "Florida"},\n    {id: "delaware", name: "Delaware"},\n    {id: "california", name: "California"},\n    {id: "texas", name: "Texas"},\n    {id: "new-york", name: "New York"},\n    {id: "washington", name: "Washington"},\n  ];\n\n  return (\n    <Autocomplete\n      className="w-[256px]"\n      placeholder="Select one"\n      selectionMode="single"\n      value={selectedKey}\n      onChange={setSelectedKey}\n    >\n      <Label>State</Label>\n      <Autocomplete.Trigger>\n        <Autocomplete.Value />\n        <Autocomplete.ClearButton />\n        <Autocomplete.Indicator className="size-3">\n          <Icon icon="gravity-ui:chevrons-expand-vertical" />\n        </Autocomplete.Indicator>\n      </Autocomplete.Trigger>\n      <Autocomplete.Popover>\n        <Autocomplete.Filter filter={contains}>\n          <SearchField autoFocus name="search" variant="secondary">\n            <SearchField.Group>\n              <SearchField.SearchIcon />\n              <SearchField.Input placeholder="Search states..." />\n              <SearchField.ClearButton />\n            </SearchField.Group>\n          </SearchField>\n          <ListBox renderEmptyState={() => <EmptyState>No results found</EmptyState>}>\n            {items.map((item) => (\n              <ListBox.Item key={item.id} id={item.id} textValue={item.name}>\n                {item.name}\n                <ListBox.ItemIndicator />\n              </ListBox.Item>\n            ))}\n          </ListBox>\n        </Autocomplete.Filter>\n      </Autocomplete.Popover>\n    </Autocomplete>\n  );\n}\n',
