  "autocomplete-default": {
    loader: () =>
      import("./autocomplete/default").then((module) => module.default),
    file: "autocomplete/default.tsx",
    source:
      '"use client";\n\nimport type {Key} from "@thenamespace/uikit";\n\nimport {\n  Autocomplete,\n  EmptyState,\n  Label,\n  ListBox,\n  SearchField,\n  Tag,\n  TagGroup,\n  useFilter,\n} from "@thenamespace/uikit";\nimport {useState} from "react";\n\nexport default function Default() {\n  const {contains} = useFilter({sensitivity: "base"});\n\n  const [selectedKeys, setSelectedKeys] = useState<Key[]>([]);\n\n  const items = [\n    {id: "florida", name: "Florida"},\n    {id: "delaware", name: "Delaware"},\n    {id: "california", name: "California"},\n    {id: "texas", name: "Texas"},\n    {id: "new-york", name: "New York"},\n    {id: "washington", name: "Washington"},\n  ];\n\n  const onRemoveTags = (keys: Set<Key>) => {\n    setSelectedKeys((prev) => prev.filter((key) => !keys.has(key)));\n  };\n\n  return (\n    <Autocomplete\n      className="w-[256px]"\n      placeholder="Select states"\n      selectionMode="multiple"\n      value={selectedKeys}\n      onChange={(keys: Key | Key[] | null) => setSelectedKeys(keys as Key[])}\n    >\n      <Label>States to Visit</Label>\n      <Autocomplete.Trigger>\n        <Autocomplete.Value>\n          {({defaultChildren, isPlaceholder, state}: any) => {\n            if (isPlaceholder || state.selectedItems.length === 0) {\n              return defaultChildren;\n            }\n\n            const selectedItemsKeys = state.selectedItems.map((item: any) => item.key);\n\n            return (\n              <TagGroup size="sm" onRemove={onRemoveTags}>\n                <TagGroup.List>\n                  {selectedItemsKeys.map((selectedItemKey: Key) => {\n                    const item = items.find((s) => s.id === selectedItemKey);\n\n                    if (!item) return null;\n\n                    return (\n                      <Tag key={item.id} id={item.id}>\n                        {item.name}\n                      </Tag>\n                    );\n                  })}\n                </TagGroup.List>\n              </TagGroup>\n            );\n          }}\n        </Autocomplete.Value>\n        <Autocomplete.Indicator />\n      </Autocomplete.Trigger>\n      <Autocomplete.Popover>\n        <Autocomplete.Filter filter={contains}>\n          <SearchField autoFocus name="search" variant="secondary">\n            <SearchField.Group>\n              <SearchField.SearchIcon />\n              <SearchField.Input placeholder="Search..." />\n              <SearchField.ClearButton />\n            </SearchField.Group>\n          </SearchField>\n          <ListBox renderEmptyState={() => <EmptyState>No results found</EmptyState>}>\n            {items.map((item) => (\n              <ListBox.Item key={item.id} id={item.id} textValue={item.name}>\n                {item.name}\n                <ListBox.ItemIndicator />\n              </ListBox.Item>\n            ))}\n          </ListBox>\n        </Autocomplete.Filter>\n      </Autocomplete.Popover>\n    </Autocomplete>\n  );\n}\n',
  },
