      '"use client";\n\nimport type {Color} from "@thenamespace/uikit";\n\nimport {Button, ColorField, ColorSwatch, Description, Form, Label} from "@thenamespace/uikit";\nimport {useState} from "react";\n\nexport function FormExample() {\n  const [value, setValue] = useState<Color | null>(null);\n  const [isSubmitting, setIsSubmitting] = useState(false);\n\n  const handleSubmit = (e: React.FormEvent) => {\n    e.preventDefault();\n\n    if (!value) {\n      return;\n    }\n\n    setIsSubmitting(true);\n\n    // Simulate API call\n    setTimeout(() => {\n      console.log("Color submitted:", {color: value.toString("hex")});\n      setValue(null);\n      setIsSubmitting(false);\n    }, 1500);\n  };\n\n  return (\n    <Form className="flex w-[280px] flex-col gap-4" onSubmit={handleSubmit}>\n      <ColorField\n        fullWidth\n        isRequired\n        className="w-full"\n        name="brand-color"\n        value={value}\n        onChange={setValue}\n      >\n        <Label>Brand Color</Label>\n        <ColorField.Group>\n          <ColorField.Prefix>\n            <ColorSwatch color={value ?? undefined} size="xs" />\n          </ColorField.Prefix>\n          <ColorField.Input placeholder="#000000" />\n        </ColorField.Group>\n        <Description>Choose your brand\'s primary color</Description>\n      </ColorField>\n      <Button\n        className="w-full"\n        isDisabled={!value}\n        isPending={isSubmitting}\n        type="submit"\n        variant="primary"\n      >\n        {isSubmitting ? "Saving..." : "Save Color"}\n      </Button>\n    </Form>\n  );\n}\n',
