      '"use client";\n\nimport {\n  Button,\n  ColorArea,\n  ColorField,\n  ColorPicker,\n  ColorSlider,\n  ColorSwatch,\n  ColorSwatchPicker,\n  Label,\n  parseColor,\n} from "@thenamespace/uikit";\nimport {Icon} from "@iconify/react";\nimport {useState} from "react";\n\nexport function Controlled() {\n  const [color, setColor] = useState(parseColor("#325578"));\n\n  const colorPresets = [\n    "#ef4444",\n    "#f97316",\n    "#eab308",\n    "#22c55e",\n    "#06b6d4",\n    "#3b82f6",\n    "#8b5cf6",\n    "#ec4899",\n    "#f43f5e",\n  ];\n\n  const shuffleColor = () => {\n    const randomHue = Math.floor(Math.random() * 360);\n    const randomSaturation = 50 + Math.floor(Math.random() * 50); // 50-100%\n    const randomLightness = 40 + Math.floor(Math.random() * 30); // 40-70%\n\n    setColor(parseColor(`hsl(${randomHue}, ${randomSaturation}%, ${randomLightness}%)`));\n  };\n\n  return (\n    <div className="flex flex-col gap-4">\n      <ColorPicker value={color} onChange={setColor}>\n        <ColorPicker.Trigger>\n          <ColorSwatch size="lg" />\n          <Label>Pick a color</Label>\n        </ColorPicker.Trigger>\n        <ColorPicker.Popover className="gap-2">\n          <ColorSwatchPicker className="justify-center pt-2" size="xs">\n            {colorPresets.map((preset) => (\n              <ColorSwatchPicker.Item key={preset} color={preset}>\n                <ColorSwatchPicker.Swatch />\n              </ColorSwatchPicker.Item>\n            ))}\n          </ColorSwatchPicker>\n          <ColorArea\n            aria-label="Color area"\n            className="max-w-full"\n            colorSpace="hsb"\n            xChannel="saturation"\n            yChannel="brightness"\n          >\n            <ColorArea.Thumb />\n          </ColorArea>\n          <div className="flex items-center gap-2 px-1">\n            <ColorSlider aria-label="Hue slider" channel="hue" className="flex-1" colorSpace="hsb">\n              <ColorSlider.Track>\n                <ColorSlider.Thumb />\n              </ColorSlider.Track>\n            </ColorSlider>\n            <Button\n              isIconOnly\n              aria-label="Shuffle color"\n              size="sm"\n              variant="tertiary"\n              onPress={shuffleColor}\n            >\n              <Icon className="size-4" icon="gravity-ui:shuffle" />\n            </Button>\n          </div>\n          <ColorField aria-label="Color field">\n            <ColorField.Group variant="secondary">\n              <ColorField.Prefix>\n                <ColorSwatch size="xs" />\n              </ColorField.Prefix>\n              <ColorField.Input />\n            </ColorField.Group>\n          </ColorField>\n        </ColorPicker.Popover>\n      </ColorPicker>\n      <p className="w-60 text-sm text-muted">\n        Selected: <span className="font-medium">{color.toString("hex")}</span>\n      </p>\n    </div>\n  );\n}\n',
