      '"use client";\n\nimport type {DateValue} from "@internationalized/date";\n\nimport {Button, DateField, DateRangePicker, Description, Label, RangeCalendar} from "@thenamespace/uikit";\nimport {getLocalTimeZone, today} from "@internationalized/date";\nimport {useState} from "react";\n\ntype DateRange = {\n  start: DateValue;\n  end: DateValue;\n};\n\nexport function Controlled() {\n  const start = today(getLocalTimeZone());\n  const [value, setValue] = useState<DateRange | null>({end: start.add({days: 4}), start});\n\n  return (\n    <div className="flex w-80 flex-col gap-4">\n      <DateRangePicker endName="endDate" startName="startDate" value={value} onChange={setValue}>\n        <Label>Trip dates</Label>\n        <DateField.Group fullWidth>\n          <DateField.Input slot="start">\n            {(segment) => <DateField.Segment segment={segment} />}\n          </DateField.Input>\n          <DateRangePicker.RangeSeparator />\n          <DateField.Input slot="end">\n            {(segment) => <DateField.Segment segment={segment} />}\n          </DateField.Input>\n          <DateField.Suffix>\n            <DateRangePicker.Trigger>\n              <DateRangePicker.TriggerIndicator />\n            </DateRangePicker.Trigger>\n          </DateField.Suffix>\n        </DateField.Group>\n        <DateRangePicker.Popover>\n          <RangeCalendar aria-label="Trip dates">\n            <RangeCalendar.Header>\n              <RangeCalendar.YearPickerTrigger>\n                <RangeCalendar.YearPickerTriggerHeading />\n                <RangeCalendar.YearPickerTriggerIndicator />\n              </RangeCalendar.YearPickerTrigger>\n              <RangeCalendar.NavButton slot="previous" />\n              <RangeCalendar.NavButton slot="next" />\n            </RangeCalendar.Header>\n            <RangeCalendar.Grid>\n              <RangeCalendar.GridHeader>\n                {(day) => <RangeCalendar.HeaderCell>{day}</RangeCalendar.HeaderCell>}\n              </RangeCalendar.GridHeader>\n              <RangeCalendar.GridBody>\n                {(date) => <RangeCalendar.Cell date={date} />}\n              </RangeCalendar.GridBody>\n            </RangeCalendar.Grid>\n            <RangeCalendar.YearPickerGrid>\n              <RangeCalendar.YearPickerGridBody>\n                {({year}) => <RangeCalendar.YearPickerCell year={year} />}\n              </RangeCalendar.YearPickerGridBody>\n            </RangeCalendar.YearPickerGrid>\n          </RangeCalendar>\n        </DateRangePicker.Popover>\n      </DateRangePicker>\n      <Description>\n        Current value: {value ? `${value.start.toString()} -> ${value.end.toString()}` : "(empty)"}\n      </Description>\n      <div className="flex gap-2">\n        <Button\n          variant="tertiary"\n          onPress={() => {\n            const nextStart = today(getLocalTimeZone());\n\n            setValue({end: nextStart.add({days: 6}), start: nextStart});\n          }}\n        >\n          Set week\n        </Button>\n        <Button variant="tertiary" onPress={() => setValue(null)}>\n          Clear\n        </Button>\n      </div>\n    </div>\n  );\n}\n',
