      '"use client";\n\nimport {DateField, DateRangePicker, Description, Label, RangeCalendar} from "@thenamespace/uikit";\nimport {Icon} from "@iconify/react";\n\nexport function WithCustomIndicator() {\n  return (\n    <DateRangePicker className="w-80" endName="endDate" startName="startDate">\n      <Label>Trip dates</Label>\n      <DateField.Group fullWidth>\n        <DateField.Input slot="start">\n          {(segment) => <DateField.Segment segment={segment} />}\n        </DateField.Input>\n        <DateRangePicker.RangeSeparator />\n        <DateField.Input slot="end">\n          {(segment) => <DateField.Segment segment={segment} />}\n        </DateField.Input>\n        <DateField.Suffix>\n          <DateRangePicker.Trigger>\n            <DateRangePicker.TriggerIndicator>\n              <Icon className="size-4" icon="gravity-ui:chevron-down" />\n            </DateRangePicker.TriggerIndicator>\n          </DateRangePicker.Trigger>\n        </DateField.Suffix>\n      </DateField.Group>\n      <Description>Replace the default calendar icon by passing custom children.</Description>\n      <DateRangePicker.Popover>\n        <RangeCalendar aria-label="Trip dates">\n          <RangeCalendar.Header>\n            <RangeCalendar.YearPickerTrigger>\n              <RangeCalendar.YearPickerTriggerHeading />\n              <RangeCalendar.YearPickerTriggerIndicator />\n            </RangeCalendar.YearPickerTrigger>\n            <RangeCalendar.NavButton slot="previous" />\n            <RangeCalendar.NavButton slot="next" />\n          </RangeCalendar.Header>\n          <RangeCalendar.Grid>\n            <RangeCalendar.GridHeader>\n              {(day) => <RangeCalendar.HeaderCell>{day}</RangeCalendar.HeaderCell>}\n            </RangeCalendar.GridHeader>\n            <RangeCalendar.GridBody>\n              {(date) => <RangeCalendar.Cell date={date} />}\n            </RangeCalendar.GridBody>\n          </RangeCalendar.Grid>\n          <RangeCalendar.YearPickerGrid>\n            <RangeCalendar.YearPickerGridBody>\n              {({year}) => <RangeCalendar.YearPickerCell year={year} />}\n            </RangeCalendar.YearPickerGridBody>\n          </RangeCalendar.YearPickerGrid>\n        </RangeCalendar>\n      </DateRangePicker.Popover>\n    </DateRangePicker>\n  );\n}\n',
