      '"use client";\n\nimport {QrCode} from "@gravity-ui/icons";\nimport {Button, Disclosure} from "@thenamespace/uikit";\nimport {Icon} from "@iconify/react";\nimport React from "react";\n\nexport function CustomRenderFunction() {\n  const [isExpanded, setIsExpanded] = React.useState(true);\n\n  return (\n    <div className="w-full max-w-md text-center">\n      <Disclosure\n        isExpanded={isExpanded}\n        render={(props) => <div {...props} data-custom="foo" />}\n        onExpandedChange={setIsExpanded}\n      >\n        <Disclosure.Heading>\n          <Button slot="trigger" variant="secondary">\n            <QrCode />\n            Preview Namespace UIKit Native\n            <Disclosure.Indicator />\n          </Button>\n        </Disclosure.Heading>\n        <Disclosure.Content render={(props) => <div data-custom="bar" {...props} />}>\n          <Disclosure.Body className="shadow-panel flex flex-col items-center rounded-3xl bg-surface p-4 text-center">\n            <p className="text-sm text-muted">\n              Scan this QR code with your camera app to preview the Namespace UIKit native components.\n            </p>\n            <img\n              alt="Expo Go QR Code"\n              className="aspect-square w-full max-w-54 object-cover"\n              src="/assets/images/qr-code-native.png"\n            />\n            <p className="text-sm text-muted">Expo must be installed on your device.</p>\n            <Button className="mt-4" variant="primary">\n              <Icon icon="tabler:brand-apple-filled" />\n              Download on App Store\n            </Button>\n          </Disclosure.Body>\n        </Disclosure.Content>\n      </Disclosure>\n    </div>\n  );\n}\n',
