    source:
      '"use client";\n\nimport {Button, Description, Form, InputOTP, Label} from "@thenamespace/uikit";\nimport React from "react";\n\nexport function WithValidation() {\n  const [value, setValue] = React.useState("");\n  const [isInvalid, setIsInvalid] = React.useState(false);\n\n  const onSubmit = (e: React.FormEvent<HTMLFormElement>) => {\n    e.preventDefault();\n    const formData = new FormData(e.currentTarget);\n    const code = formData.get("code");\n\n    if (code !== "123456") {\n      setIsInvalid(true);\n\n      return;\n    }\n\n    setIsInvalid(false);\n    setValue("");\n\n    alert("Code verified successfully!");\n  };\n\n  const handleChange = (val: string) => {\n    setValue(val);\n    setIsInvalid(false);\n  };\n\n  return (\n    <div className="flex w-[280px] flex-col gap-2">\n      <Form className="flex flex-col gap-2" onSubmit={onSubmit}>\n        <Label>Verify account</Label>\n        <Description>Hint: The code is 123456</Description>\n        <InputOTP\n          aria-describedby={isInvalid ? "code-error" : undefined}\n          isInvalid={isInvalid}\n          maxLength={6}\n          name="code"\n          value={value}\n          onChange={handleChange}\n        >\n          <InputOTP.Group>\n            <InputOTP.Slot index={0} />\n            <InputOTP.Slot index={1} />\n            <InputOTP.Slot index={2} />\n          </InputOTP.Group>\n          <InputOTP.Separator />\n          <InputOTP.Group>\n            <InputOTP.Slot index={3} />\n            <InputOTP.Slot index={4} />\n            <InputOTP.Slot index={5} />\n          </InputOTP.Group>\n        </InputOTP>\n        <span className="field-error" data-visible={isInvalid} id="code-error">\n          Invalid code. Please try again.\n        </span>\n        <Button isDisabled={value.length !== 6} type="submit">\n          Submit\n        </Button>\n      </Form>\n    </div>\n  );\n}\n',
