      '"use client";\n\nimport {Label, ListBox, NumberField, ProgressBar, Select, Separator} from "@thenamespace/uikit";\nimport {useState} from "react";\n\nconst formatStyleOptions: {label: string; value: string}[] = [\n  {label: "Currency", value: "currency"},\n  {label: "Percent", value: "percent"},\n  {label: "Decimal", value: "decimal"},\n  {label: "Unit", value: "unit"},\n];\n\nconst formatOptionsMap: Record<string, Intl.NumberFormatOptions> = {\n  currency: {currency: "USD", style: "currency"},\n  decimal: {style: "decimal"},\n  percent: {style: "percent"},\n  unit: {style: "unit", unit: "mile"},\n};\n\nexport function CustomValue() {\n  const [value, setValue] = useState(750);\n  const [minValue, setMinValue] = useState(0);\n  const [maxValue, setMaxValue] = useState(1000);\n  const [format, setFormat] = useState<string>("percent");\n\n  return (\n    <div className="flex w-full flex-col gap-6 md:flex-row md:items-center md:gap-10">\n      <div className="flex w-full max-w-md flex-1 justify-center">\n        <ProgressBar\n          aria-label="Revenue"\n          className="w-full max-w-52"\n          formatOptions={formatOptionsMap[format]}\n          maxValue={maxValue}\n          minValue={minValue}\n          value={value}\n        >\n          <Label>Progress</Label>\n          <ProgressBar.Output />\n          <ProgressBar.Track>\n            <ProgressBar.Fill />\n          </ProgressBar.Track>\n        </ProgressBar>\n      </div>\n\n      <Separator className="md:hidden" />\n      <Separator className="hidden md:block" orientation="vertical" />\n\n      <div className="flex max-w-52 flex-col gap-3">\n        <Label className="text-xs font-medium text-muted">Options</Label>\n\n        <NumberField\n          maxValue={maxValue}\n          minValue={minValue}\n          value={value}\n          variant="secondary"\n          onChange={(v) => setValue(v)}\n        >\n          <Label>Value</Label>\n          <NumberField.Group>\n            <NumberField.DecrementButton />\n            <NumberField.Input />\n            <NumberField.IncrementButton />\n          </NumberField.Group>\n        </NumberField>\n\n        <NumberField\n          maxValue={maxValue - 1}\n          minValue={0}\n          value={minValue}\n          variant="secondary"\n          onChange={(v) => {\n            setMinValue(v);\n            if (value < v) setValue(v);\n          }}\n        >\n          <Label>Min Value</Label>\n          <NumberField.Group>\n            <NumberField.DecrementButton />\n            <NumberField.Input />\n            <NumberField.IncrementButton />\n          </NumberField.Group>\n        </NumberField>\n\n        <NumberField\n          maxValue={2000}\n          minValue={minValue + 1}\n          value={maxValue}\n          variant="secondary"\n          onChange={(v) => {\n            setMaxValue(v);\n            if (value > v) setValue(v);\n          }}\n        >\n          <Label>Max Value</Label>\n          <NumberField.Group>\n            <NumberField.DecrementButton />\n            <NumberField.Input />\n            <NumberField.IncrementButton />\n          </NumberField.Group>\n        </NumberField>\n\n        <Select value={format} variant="secondary" onChange={(key) => setFormat(key as string)}>\n          <Label>Format</Label>\n          <Select.Trigger>\n            <Select.Value />\n            <Select.Indicator />\n          </Select.Trigger>\n          <Select.Popover>\n            <ListBox>\n              {formatStyleOptions.map((option) => (\n                <ListBox.Item key={option.value} id={option.value} textValue={option.label}>\n                  {option.label}\n                  <ListBox.ItemIndicator />\n                </ListBox.Item>\n              ))}\n            </ListBox>\n          </Select.Popover>\n        </Select>\n      </div>\n    </div>\n  );\n}\n',
