  "table-custom-cells": {
    loader: () =>
      import("./table/custom-cells").then((module) => module.CustomCells),
    file: "table/custom-cells.tsx",
    source:
      '"use client";\n\nimport type {Selection, SortDescriptor} from "@thenamespace/uikit";\n\nimport {Avatar, Button, Checkbox, Chip, Table} from "@thenamespace/uikit";\nimport {Icon} from "@iconify/react";\nimport {useMemo, useState} from "react";\n\ninterface User {\n  id: number;\n  name: string;\n  image_url: string;\n  role: string;\n  status: "Active" | "Inactive" | "On Leave";\n  email: string;\n}\n\nconst statusColorMap: Record<string, "success" | "danger" | "warning"> = {\n  Active: "success",\n  Inactive: "danger",\n  "On Leave": "warning",\n};\n\nconst users: User[] = [\n  {\n    email: "kate@acme.com",\n    id: 4586932,\n    image_url: "/assets/avatars/red.jpg",\n    name: "Kate Moore",\n    role: "Chief Executive Officer",\n    status: "Active",\n  },\n  {\n    email: "john@acme.com",\n    id: 5273849,\n    image_url: "/assets/avatars/green.jpg",\n    name: "John Smith",\n    role: "Chief Technology Officer",\n    status: "Active",\n  },\n  {\n    email: "sara@acme.com",\n    id: 7492836,\n    image_url: "/assets/avatars/blue.jpg",\n    name: "Sara Johnson",\n    role: "Chief Marketing Officer",\n    status: "On Leave",\n  },\n  {\n    email: "michael@acme.com",\n    id: 8293746,\n    image_url: "/assets/avatars/purple.jpg",\n    name: "Michael Brown",\n    role: "Chief Financial Officer",\n    status: "Active",\n  },\n  {\n    email: "emily@acme.com",\n    id: 1234567,\n    image_url: "/assets/avatars/orange.jpg",\n    name: "Emily Davis",\n    role: "Product Manager",\n    status: "Inactive",\n  },\n];\n\nexport function CustomCells() {\n  const [selectedKeys, setSelectedKeys] = useState<Selection>(new Set());\n  const [sortDescriptor, setSortDescriptor] = useState<SortDescriptor>({\n    column: "name",\n    direction: "ascending",\n  });\n\n  const sortedUsers = useMemo(() => {\n    return [...users].sort((a, b) => {\n      const col = sortDescriptor.column as keyof User;\n      const first = String(a[col]);\n      const second = String(b[col]);\n      let cmp = first.localeCompare(second);\n\n      if (sortDescriptor.direction === "descending") {\n        cmp *= -1;\n      }\n\n      return cmp;\n    });\n  }, [sortDescriptor]);\n\n  return (\n    <Table>\n      <Table.ScrollContainer>\n        <Table.Content\n          aria-label="Table with custom cells"\n          className="min-w-[800px]"\n          selectedKeys={selectedKeys}\n          selectionMode="multiple"\n          sortDescriptor={sortDescriptor}\n          onSelectionChange={setSelectedKeys}\n          onSortChange={setSortDescriptor}\n        >\n          <Table.Header>\n            <Table.Column className="pr-0">\n              <Checkbox aria-label="Select all" slot="selection">\n                <Checkbox.Content>\n                  <Checkbox.Control>\n                    <Checkbox.Indicator />\n                  </Checkbox.Control>\n                </Checkbox.Content>\n              </Checkbox>\n            </Table.Column>\n            <Table.Column allowsSorting isRowHeader className="after:hidden" id="id">\n              {({sortDirection}) => (\n                <Table.SortableColumnHeader sortDirection={sortDirection}>\n                  Worker ID\n                </Table.SortableColumnHeader>\n              )}\n            </Table.Column>\n            <Table.Column allowsSorting id="name">\n              {({sortDirection}) => (\n                <Table.SortableColumnHeader sortDirection={sortDirection}>\n                  Member\n                </Table.SortableColumnHeader>\n              )}\n            </Table.Column>\n            <Table.Column allowsSorting id="role">\n              {({sortDirection}) => (\n                <Table.SortableColumnHeader sortDirection={sortDirection}>\n                  Role\n                </Table.SortableColumnHeader>\n              )}\n            </Table.Column>\n            <Table.Column allowsSorting id="status">\n              {({sortDirection}) => (\n                <Table.SortableColumnHeader sortDirection={sortDirection}>\n                  Status\n                </Table.SortableColumnHeader>\n              )}\n            </Table.Column>\n            <Table.Column className="text-end">Actions</Table.Column>\n          </Table.Header>\n          <Table.Body>\n            {sortedUsers.map((user) => (\n              <Table.Row key={user.id} id={user.id}>\n                <Table.Cell className="pr-0">\n                  <Checkbox aria-label={`Select ${user.name}`} slot="selection" variant="secondary">\n                    <Checkbox.Content>\n                      <Checkbox.Control>\n                        <Checkbox.Indicator />\n                      </Checkbox.Control>\n                    </Checkbox.Content>\n                  </Checkbox>\n                </Table.Cell>\n                <Table.Cell className="font-medium">\n                  <div className="flex items-center gap-2">\n                    #{user.id.toString()}{" "}\n                    <Button isIconOnly size="sm" variant="ghost">\n                      <Icon className="size-4 text-muted" icon="gravity-ui:copy" />\n                    </Button>\n                  </div>\n                </Table.Cell>\n                <Table.Cell>\n                  <div className="flex items-center gap-3">\n                    <Avatar size="sm">\n                      <Avatar.Image src={user.image_url} />\n                      <Avatar.Fallback>\n                        {user.name\n                          .split(" ")\n                          .map((n) => n[0])\n                          .join("")}\n                      </Avatar.Fallback>\n                    </Avatar>\n                    <div className="flex flex-col">\n                      <span className="text-xs">{user.name}</span>\n                      <span className="text-xs text-muted">{user.email}</span>\n                    </div>\n                  </div>\n                </Table.Cell>\n                <Table.Cell className="min-w-52">{user.role}</Table.Cell>\n                <Table.Cell className="min-w-25">\n                  <Chip color={statusColorMap[user.status]} size="sm" variant="soft">\n                    {user.status}\n                  </Chip>\n                </Table.Cell>\n                <Table.Cell>\n                  <div className="flex items-center gap-1">\n                    <Button isIconOnly size="sm" variant="tertiary">\n                      <Icon className="size-4" icon="gravity-ui:eye" />\n                    </Button>\n                    <Button isIconOnly size="sm" variant="tertiary">\n                      <Icon className="size-4" icon="gravity-ui:pencil" />\n                    </Button>\n                    <Button isIconOnly size="sm" variant="danger-soft">\n                      <Icon className="size-4" icon="gravity-ui:trash-bin" />\n                    </Button>\n                  </div>\n                </Table.Cell>\n              </Table.Row>\n            ))}\n          </Table.Body>\n        </Table.Content>\n      </Table.ScrollContainer>\n    </Table>\n  );\n}\n',
  },
